    const stack = [];
    stack.push({ x: startX, y: startY, len: baseLen, angleDeg: 90, depth: depth, thickness: Math.max(1, depth / 2 + 1) });

    // We'll draw from bottom-up style by popping; if you want depth-first left-first, push in reverse
    while (stack.length) {
      const frame = stack.pop();
      const { x, y, len, angleDeg, depth: d, thickness } = frame;
      if (d <= 0 || len < 0.5) continue;

      // line style based on depth
      const t = d / depth;
      ctx.strokeStyle = `hsl(${30 + 70 * (1 - t)}, ${20 + 40*t}%, ${20 + 45*t}%)`;
