      const newLen = len * ratio;
      const nextDepth = d - 1;
      const childThickness = Math.max(0.6, thickness * 0.75);

      // right child
      stack.push({ x: x2, y: y2, len: newLen, angleDeg: angleDeg + branchAngle, depth: nextDepth, thickness: childThickness });
