      while (q.length) {
        const cur = q.shift();
        if (cur.depth <= 1) {
          const rad = (cur.angleDeg) * Math.PI / 180;
          const tx = cur.x + Math.cos(rad) * cur.len;
          const ty = cur.y - Math.sin(rad) * cur.len;
          ctx.beginPath();
          ctx.arc(tx, ty, Math.max(1.5, cur.len * 0.06), 0, Math.PI * 2);
          ctx.fill();
          continue;
        }
        const newLen = cur.len * ratio;
        q.push({ x: cur.x + Math.cos(cur.angleDeg * Math.PI / 180) * cur.len, y: cur.y - Math.sin(cur.angleDeg * Math.PI / 180) * cur.len, len: newLen, angleDeg: cur.angleDeg - branchAngle, depth: cur.depth - 1 });
        q.push({ x: cur.x + Math.cos(cur.angleDeg * Math.PI / 180) * cur.len, y: cur.y - Math.sin(cur.angleDeg * Math.PI / 180) * cur.len, len: newLen, angleDeg: cur.angleDeg + branchAngle, depth: cur.depth - 1 });
      }
    }
  }

